// Synthesized mechanical switch click sound
const playClickSound = () => {
  try {
    const audioCtx = new (window.AudioContext || window.webkitAudioContext)()

    // High-pitched click snap
    const osc1 = audioCtx.createOscillator()
    const gain1 = audioCtx.createGain()
    osc1.type = 'triangle'
    osc1.frequency.setValueAtTime(1100, audioCtx.currentTime)
    osc1.frequency.exponentialRampToValueAtTime(150, audioCtx.currentTime + 0.05)
    gain1.gain.setValueAtTime(0.2, audioCtx.currentTime)
    gain1.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.05)

    osc1.connect(gain1)
    gain1.connect(audioCtx.destination)

    // Low-frequency key tap sound
    const osc2 = audioCtx.createOscillator()
    const gain2 = audioCtx.createGain()
    osc2.type = 'sine'
    osc2.frequency.setValueAtTime(140, audioCtx.currentTime)
    osc2.frequency.exponentialRampToValueAtTime(30, audioCtx.currentTime + 0.08)
    gain2.gain.setValueAtTime(0.3, audioCtx.currentTime)
    gain2.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.08)

    osc2.connect(gain2)
    gain2.connect(audioCtx.destination)

    osc1.start()
    osc1.stop(audioCtx.currentTime + 0.06)

    osc2.start()
    osc2.stop(audioCtx.currentTime + 0.1)
  } catch (e) {
    console.log('Audio Context click sound error: ', e)
  }
}

